svg.script:

console.clear();
console.log('═══════════════════════════════════════');
console.log('🔍 BLOB URL ORIGIN TEST');
console.log('═══════════════════════════════════════');
console.log('📍 Current URL:', window.location.href);
console.log('📍 URL scheme:', window.location.protocol);
console.log('📍 Origin:', window.location.origin);
console.log('📍 Hostname:', window.location.hostname);

// Check if this is a blob URL
if (window.location.href.startsWith('blob:')) {
    console.log('✅ This IS a blob URL');
    console.log('📌 Origin should be:', window.location.origin);

    // Check if origin matches ai.planet.com
    if (window.location.origin === 'https://ai.planet.com') {
        console.log('✅ Origin matches https://ai.planet.com');
        console.log('✅ frame-ancestors "self" should allow this');
        console.log('📌 Iframe should load successfully!');
    } else {
        console.log('⚠️ Origin is:', window.location.origin);
        console.log('📌 This may not match "self" or firebaseapp.com');
    }
} else {
    console.log('❌ This is NOT a blob URL');
    console.log('📌 URL type:', window.location.href);
}

// Monitor iframe
setTimeout(function() {
    var iframe = document.querySelector('iframe');
    if (iframe) {
        console.log('\n📌 Iframe status:');
        try {
            var doc = iframe.contentDocument || iframe.contentWindow?.document;
            if (doc && doc.body && doc.body.innerHTML.length > 0) {
                console.log('✅ IFRAME CONTENT LOADED!');
                console.log('📝 Title:', doc.title);
                console.log('📝 Content length:', doc.body.innerHTML.length);
            } else {
                console.log('⏳ Iframe loaded but content not accessible');
            }
        } catch(e) {
            console.log('⏳ Iframe loaded, CORS prevents content access');
            console.log('📌 This is normal if cross-origin');
        }
    }
}, 3000);

console.log('\n═══════════════════════════════════════');
